return [
  {
    json: {
      transcript_source_url: 'https://www.youtube.com/watch?v=example',
      source_name: 'Manual video ingest',
      source_type: 'transcript',
      media_type: 'video'
    }
  }
];

return {
  json: {
    ...$json,
    transcript_api_request: {
      base_url: $env.VIDEO_TRANSCRIPT_BASE_URL || 'set-in-env',
      endpoint: '/api/transcribe',
      method: 'POST',
      body: {
        url: $json.transcript_source_url
      }
    }
  }
};

return {
  json: {
    ...$json,
    upstream_task_id: 'task_123456',
    upstream_view_token: 'view_token_123456',
    upstream_summary: 'Optional upstream summary for reference only.',
    canonical_url: $json.transcript_source_url,
    original_id: 'youtube:example',
    title: 'Example transcript item',
    author: 'Example creator',
    published_at: '2026-04-17T09:00:00-04:00',
    transcript_text: 'Calibrated transcript text fetched from /view/{token}?raw=calibrated.'
  }
};

const crypto = require('crypto');

const stableHash = (value) => crypto.createHash('sha256').update(String(value), 'utf8').digest('hex');
const publishedAt = new Date($json.published_at || Date.now()).toISOString();
const ingestedAt = new Date().toISOString();
const canonicalUrl = String($json.canonical_url || '').trim();
const sourceType = String($json.source_type || 'transcript').trim() || 'transcript';
const originalId = String($json.original_id || '').trim();
const title = String($json.title || 'untitled').trim() || 'untitled';
const author = String($json.author || '').trim();
const contentText = String($json.transcript_text || '').trim();
const itemKey = canonicalUrl || (sourceType && originalId ? `${sourceType}:${originalId}` : '') || [title, publishedAt, author].filter(Boolean).join('::');
const itemId = stableHash(itemKey);

return {
  json: {
    item_id: itemId,
    source_type: sourceType,
    source_name: String($json.source_name || 'video-transcript-api').trim() || 'video-transcript-api',
    original_id: originalId,
    canonical_url: canonicalUrl,
    title,
    author,
    published_at: publishedAt,
    ingested_at: ingestedAt,
    media_type: String($json.media_type || 'video').trim() || 'video',
    content_text: contentText,
    content_html: '',
    upstream_task_id: String($json.upstream_task_id || '').trim(),
    upstream_view_token: String($json.upstream_view_token || '').trim(),
    upstream_summary: String($json.upstream_summary || '').trim(),
    content_hash: `sha256:${stableHash(contentText)}`,
    score: 0,
    category: 'pending',
    tags: ['inbox', 'ai-information-processor', 'transcript'],
    dedupe_action: 'full_push',
    status: 'raw',
    vault_path: ''
  }
};
